// ── LOGO ─────────────────────────────────────────────────
// OPCIÓN A (recomendada): pega aquí el Data URI base64 del logo PNG o SVG.
// Cuando está definido, se usa en la app web Y en el PDF sin problemas de CORS.
// Ejemplo PNG: "data:image/png;base64,iVBORw0KGgo..."
// Ejemplo SVG: "data:image/svg+xml;base64,PHN2ZyB4bWxu..."
const LOGO_DATA_URL = "data:image/svg+xml;base64,";

// OPCIÓN B (fallback): URL pública de Google Drive.
// Solo se usa para mostrar el logo en la app web cuando LOGO_DATA_URL está vacío.
// Para PDF se convierte a base64 en tiempo de ejecución (puede fallar por CORS).
const LOGO_URL = "https://drive.google.com/uc?export=view&id=1LnTQZzMonpDju9EMe_iWAfw0WvB5y6sn";

// Caché del logo en base64 para PDF (evita re-conversión en cada descarga)
let _logoBase64Cache = null;

async function _obtenerLogoBase64() {
  if (_logoBase64Cache) return _logoBase64Cache;
  const src = LOGO_DATA_URL || LOGO_URL;
  if (!src) return null;
  return new Promise(resolve => {
    const img = new Image();
    if (!src.startsWith("data:")) img.crossOrigin = "anonymous";
    img.onload = () => {
      try {
        const c = document.createElement("canvas");
        c.width = img.naturalWidth || 400;
        c.height = img.naturalHeight || 110;
        const ctx2d = c.getContext("2d");
        ctx2d.fillStyle = "#ffffff";
        ctx2d.fillRect(0, 0, c.width, c.height);
        ctx2d.drawImage(img, 0, 0);
        _logoBase64Cache = c.toDataURL("image/png");
        resolve(_logoBase64Cache);
      } catch(e) { resolve(LOGO_DATA_URL || null); }
    };
    img.onerror = () => resolve(LOGO_DATA_URL || null);
    img.src = src.startsWith("data:") ? src : src + (src.includes("?") ? "&" : "?") + "_nocache=" + Date.now();
  });
}

// ── LOGIN CANVAS ANIMATION ───────────────────────────────
(function _initLoginCanvas() {
  var canvas, ctx, pts, raf, W, H;
  var mouse = { x: -9999, y: -9999 };
  var N = 65, LINK = 140, REPEL = 90, SPEED = 0.3;

  function rand(a, b) { return a + Math.random() * (b - a); }
  function resize() { W = canvas.width = canvas.offsetWidth; H = canvas.height = canvas.offsetHeight; }
  function mkPt() { return { x: rand(0,W), y: rand(0,H), vx: rand(-SPEED,SPEED)||SPEED, vy: rand(-SPEED,SPEED)||SPEED, r: rand(1,2.5) }; }

  function draw() {
    var scr = document.getElementById("screen-login");
    if (!scr || !scr.classList.contains("active")) { cancelAnimationFrame(raf); return; }
    ctx.clearRect(0, 0, W, H);
    for (var i = 0; i < pts.length; i++) {
      var p = pts[i];
      var dx = p.x - mouse.x, dy = p.y - mouse.y, d2 = dx*dx + dy*dy;
      if (d2 < REPEL*REPEL && d2 > 0) {
        var d = Math.sqrt(d2), f = (REPEL - d) / REPEL * 1.5;
        p.vx += dx/d * f * 0.04; p.vy += dy/d * f * 0.04;
      }
      var spd = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
      if (spd > SPEED*3) { p.vx = p.vx/spd*SPEED*3; p.vy = p.vy/spd*SPEED*3; }
      if (spd < SPEED*0.4) { p.vx *= 1.03; p.vy *= 1.03; }
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0) { p.x = 0; p.vx *= -1; } if (p.x > W) { p.x = W; p.vx *= -1; }
      if (p.y < 0) { p.y = 0; p.vy *= -1; } if (p.y > H) { p.y = H; p.vy *= -1; }
      ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
      ctx.fillStyle = "rgba(124,131,253,0.22)"; ctx.fill();
      for (var j = i+1; j < pts.length; j++) {
        var q = pts[j], ex = p.x-q.x, ey = p.y-q.y, ed = Math.sqrt(ex*ex+ey*ey);
        if (ed < LINK) {
          var a = (1 - ed/LINK) * 0.25;
          ctx.beginPath(); ctx.moveTo(p.x,p.y); ctx.lineTo(q.x,q.y);
          ctx.strokeStyle = "rgba(199,210,254,"+a+")"; ctx.lineWidth = 0.8; ctx.stroke();
        }
      }
    }
    raf = requestAnimationFrame(draw);
  }

  function start() {
    canvas = document.getElementById("login-canvas");
    if (!canvas) return;
    ctx = canvas.getContext("2d");
    resize();
    pts = Array.from({ length: N }, mkPt);
    window.addEventListener("resize", resize);
    var scr = document.getElementById("screen-login");
    (scr || canvas).addEventListener("mousemove", function(e) {
      var r = canvas.getBoundingClientRect();
      mouse.x = e.clientX - r.left; mouse.y = e.clientY - r.top;
    });
    (scr || canvas).addEventListener("mouseleave", function() { mouse.x = -9999; mouse.y = -9999; });
    raf = requestAnimationFrame(draw);
  }

  window._restartLoginCanvas = function() {
    if (raf) cancelAnimationFrame(raf);
    setTimeout(function() { start(); }, 50);
  };

  document.addEventListener("DOMContentLoaded", function() {
    start();
    // Insertar logo (prioriza base64 sobre URL de Drive)
    var logoSrc = LOGO_DATA_URL || LOGO_URL;
    if (logoSrc) {
      var loginImg   = document.getElementById("login-logo-img");
      var loginFb    = document.getElementById("login-logo-fallback");
      var headerImg  = document.getElementById("header-logo-img");
      var headerFb   = document.getElementById("header-logo-fallback");
      var headerDiv  = document.getElementById("header-logo-divider");
      if (loginImg)  { loginImg.src = logoSrc;  loginImg.style.display  = "block"; }
      if (loginFb)   { loginFb.style.display  = "none"; }
      if (headerImg) { headerImg.src = logoSrc; headerImg.style.display = "block"; }
      if (headerFb)  { headerFb.style.display  = "none"; }
      if (headerDiv) { headerDiv.style.display = "block"; }
    }
  });
})();

// ── GMAIL TOKEN ──────────────────────────────────────────
const _SS_GMAIL_KEY = 'pazysalvo_gmail_token';
const _SS_GMAIL_EXP = 'pazysalvo_gmail_exp';
let _gmailToken    = null;
let _gmailTokenExp = 0;

function _cargarTokenGmailSesion() {
  try {
    const t = sessionStorage.getItem(_SS_GMAIL_KEY);
    const e = parseInt(sessionStorage.getItem(_SS_GMAIL_EXP) || '0', 10);
    if (t && Date.now() < e) { _gmailToken = t; _gmailTokenExp = e; }
  } catch(e) {}
}

function _limpiarTokenGmail() {
  _gmailToken = null; _gmailTokenExp = 0;
  try { sessionStorage.removeItem(_SS_GMAIL_KEY); sessionStorage.removeItem(_SS_GMAIL_EXP); } catch(e) {}
}

function _pedirGmailToken() {
  if (_gmailToken && Date.now() < _gmailTokenExp) return Promise.resolve(_gmailToken);
  return new Promise((resolve, reject) => {
    if (!window.google) { reject(new Error('GIS no cargado')); return; }
    const client = google.accounts.oauth2.initTokenClient({
      client_id: GOOGLE_CLIENT_ID,
      scope: 'https://www.googleapis.com/auth/gmail.send',
      callback: (resp) => {
        if (resp.error) { reject(new Error(resp.error)); return; }
        _gmailToken    = resp.access_token;
        _gmailTokenExp = Date.now() + (resp.expires_in - 60) * 1000;
        try {
          sessionStorage.setItem(_SS_GMAIL_KEY, _gmailToken);
          sessionStorage.setItem(_SS_GMAIL_EXP, String(_gmailTokenExp));
        } catch(e) {}
        setTimeout(() => { _gmailToken = null; }, (resp.expires_in - 60) * 1000);
        resolve(_gmailToken);
      }
    });
    client.requestToken();
  });
}

async function _enviarCorreoGmail(para, asunto, cuerpo) {
  try {
    const token = await _pedirGmailToken();
    const msg = [
      'To: ' + para,
      'Subject: =?UTF-8?B?' + btoa(unescape(encodeURIComponent(asunto))) + '?=',
      'Content-Type: text/plain; charset=UTF-8',
      'MIME-Version: 1.0',
      '',
      cuerpo
    ].join('\r\n');
    const b64 = btoa(unescape(encodeURIComponent(msg)))
      .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
    const res = await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages/send', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
      body: JSON.stringify({ raw: b64 })
    });
    if (!res.ok) throw new Error('Gmail API ' + res.status);
    return true;
  } catch(e) {
    console.warn('Error enviando correo:', e);
    return false;
  }
}

