function buildSidebar(rv) {
  const sidebar = document.getElementById("sidebar");
  const items   = MENUS[rv || STATE.rol] || [];
  sidebar.innerHTML = items.map(item => {
    if (item.section) return `<div class="sidebar-section-title">${item.section}</div>`;
    return `<div class="sidebar-item" id="nav-${item.id}" onclick="navigateTo('${item.id}')">
      <span class="icon">${item.icon}</span> ${item.label}
    </div>`;
  }).join("");
}

function navigateTo(panelId) {
  document.querySelectorAll(".sidebar-item").forEach(el => el.classList.remove("active"));
  const navEl = document.getElementById(`nav-${panelId}`);
  if (navEl) navEl.classList.add("active");

  document.querySelectorAll(".content-panel").forEach(p => p.classList.remove("active"));
  const panel = document.getElementById(`panel-${panelId}`);
  if (panel) panel.classList.add("active");

  if      (panelId === "mi-estado")           loadMiEstado();
  else if (panelId === "solicitud-th")        loadPanelEnviarPazSalvo();
  else if (panelId === "area-colaboradores")  loadAreaColaboradores();
  else if (panelId === "admin-config")        loadAdminConfig();
  else if (panelId === "sa-colaboradores")    loadSAColaboradores();
  else if (panelId === "sa-usuarios")         loadSAUsuarios();
  else if (panelId === "sa-config")           { loadSAConfig(); loadCorreosSA(); }
  else if (panelId === "sa-global")           loadSAGlobal();
  else if (panelId === "sa-logs")             loadLogs();
}

// ═══════════════════════════════════════════════════════
// COLABORADOR — MI ESTADO
// ═══════════════════════════════════════════════════════
async function loadMiEstado() {
  const container = document.getElementById("mi-estado-content");

  // Todos los roles usan STATE.cedulaPropia (guardada al login o al vincular manualmente)
  let cedula;
  if (STATE.cedulaPropia) {
    cedula = STATE.cedulaPropia;
  } else {
    // Sin cédula vinculada: aplica a cualquier rol (incluido COLABORADOR que entró por Google)
    container.innerHTML = `
      <div class="empty-state">
        <div class="empty-icon">👤</div>
        <h3>Ingresa tu cédula</h3>
        <p style="color:var(--text2); margin-bottom:1.5rem; max-width:380px">
          Para ver tu estado, ingresa tu número de cédula.
          Solo se pide una vez por sesión.
        </p>
        <div style="display:flex; gap:8px; justify-content:center; flex-wrap:wrap">
          <input type="text" id="admin-cedula-input" class="form-input"
            style="width:200px; text-align:center; font-family:var(--font-mono); font-size:1rem"
            placeholder="Ej: 12345678" oninput="this.value=this.value.replace(/[^0-9]/g,'')"
            onkeydown="if(event.key==='Enter') vincularCedulaAdmin()">
          <button class="btn btn-primary" onclick="vincularCedulaAdmin()">Consultar</button>
        </div>
      </div>`;
    return;
  }

  const r = await api("get_mi_estado", { cedula });
  if (!r.ok) {
    container.innerHTML = `<div class="empty-state"><div class="empty-icon">⚠️</div><h3>${r.error}</h3></div>`;
    return;
  }

  const { colaborador, estadoPorArea, pazYSalvoCompleto, requierePazSalvo } = r;

  container.innerHTML = `
    <div class="collab-status-card">
      <div style="display:flex; align-items:flex-start; justify-content:space-between; flex-wrap:wrap; gap:1rem">
        <div>
          <div class="collab-name">${colaborador.nombre}</div>
          <div class="collab-cedula">CC ${colaborador.cedula}</div>
        </div>
        <span class="badge ${pazYSalvoCompleto ? "badge-completo" : "badge-pendiente"}">
          ${pazYSalvoCompleto ? "✓ Paz y Salvo Completo" : "En proceso"}
        </span>
      </div>
      ${!requierePazSalvo ? `<div style="margin-top:1rem; padding:1rem; background:var(--surface2); border-radius:8px; color:var(--text2); font-size:0.875rem">
        ℹ️ No requieres paz y salvo en este proceso.
      </div>` : ""}
      <div class="area-list">
        ${estadoPorArea.map(area => `
          <div class="area-item">
            <div class="area-item-left">
              <div class="area-dot ${area.estado.toLowerCase()}"></div>
              <div>
                <div style="font-weight:500">${area.areaNombre}</div>
                ${area.estado === "OMITIDO"
                  ? `<div style="font-size:0.75rem; color:#818cf8; margin-top:2px">Área propia — no requiere aprobación externa</div>`
                  : ""}
                ${area.estado === "PENDIENTE" && area.adminUsername
                  ? `<div style="font-size:0.75rem; color:var(--text2); margin-top:2px">⏳ Pendiente con: <strong>${area.adminUsername}</strong></div>`
                  : ""}
                ${area.estado === "APROBADO" && area.aprobadoPor
                  ? `<div style="font-size:0.75rem; color:var(--green); margin-top:2px">✓ Aprobado por: ${area.aprobadoPor}</div>`
                  : ""}
                ${area.estado !== "OMITIDO" && area.observaciones ? `<div style="font-size:0.78rem; color:var(--red); margin-top:2px">⚠ ${area.observaciones}</div>` : ""}
              </div>
            </div>
            <span class="badge badge-${area.estado.toLowerCase()}">${area.estado}</span>
          </div>
        `).join("")}
      </div>
    </div>
    ${pazYSalvoCompleto ? `
      <div style="margin-top:1.5rem; display:flex; gap:0.75rem; justify-content:center; flex-wrap:wrap">
        <button class="btn btn-success btn-lg" onclick="descargarDocumento('${colaborador.id}')">
          📄 Ver Paz y Salvo
        </button>
        <button class="btn btn-ghost btn-lg" onclick="descargarDocumentoImprimir('${colaborador.id}')">
          ⬇️ Descargar PDF
        </button>
      </div>
    ` : requierePazSalvo ? `
      <div style="margin-top:1.25rem; text-align:center">
        <button class="btn btn-ghost" onclick="enviarRecordatorioPropio('${colaborador.cedula}')">
          📧 Recordar a áreas pendientes
        </button>
      </div>
    ` : ""}
  `;
}

async function vincularCedulaAdmin() {
  const input  = document.getElementById("admin-cedula-input");
  if (!input) return;
  const cedula = input.value.trim();
  if (!cedula) { toast("Ingresa tu número de cédula", "error"); return; }

  const container = document.getElementById("mi-estado-content");
  container.innerHTML = '<div class="table-loading">Verificando...</div>';

  const r = await api("get_mi_estado", { cedula });
  if (!r.ok) {
    container.innerHTML = `
      <div class="empty-state">
        <div class="empty-icon">⚠️</div>
        <h3>${r.error}</h3>
        <p style="color:var(--text2); margin-bottom:1.5rem">Verifica que la cédula corresponda a un colaborador registrado.</p>
        <div style="display:flex; gap:8px; justify-content:center; flex-wrap:wrap">
          <input type="text" id="admin-cedula-input" class="form-input"
            style="width:200px; text-align:center; font-family:var(--font-mono); font-size:1rem"
            placeholder="Ej: 12345678" value="${cedula}"
            oninput="this.value=this.value.replace(/[^0-9]/g,'')"
            onkeydown="if(event.key==='Enter') vincularCedulaAdmin()">
          <button class="btn btn-primary" onclick="vincularCedulaAdmin()">Reintentar</button>
        </div>
      </div>`;
    return;
  }

  STATE.cedulaPropia = cedula;
  loadMiEstado();
}

// ═══════════════════════════════════════════════════════
// COLABORADOR — ENVIAR PAZ Y SALVO A TALENTO HUMANO
// ═══════════════════════════════════════════════════════
async function loadPanelEnviarPazSalvo() {
  const container = document.getElementById("th-panel-content");
  const cedula = STATE.cedulaPropia;

  if (!cedula) {
    container.innerHTML = `
      <div class="alert-banner warning">
        <span>⚠️</span>
        <div>Primero ve a <strong>Mi Estado</strong> e ingresa tu cédula para vincular tu perfil de colaborador.</div>
      </div>`;
    return;
  }
  const r = await api("get_mi_estado", { cedula });

  if (!r.ok) {
    container.innerHTML = `<div class="empty-state"><div class="empty-icon">⚠️</div><h3>${r.error}</h3></div>`;
    return;
  }

  const { pazYSalvoCompleto, requierePazSalvo, colaborador } = r;

  if (!requierePazSalvo) {
    container.innerHTML = `
      <div class="alert-banner info" style="max-width:600px">
        <span>ℹ️</span>
        <div>No requieres paz y salvo en este proceso. Esta sección no aplica para ti.</div>
      </div>`;
    return;
  }

  if (!pazYSalvoCompleto) {
    container.innerHTML = `
      <div class="config-card" style="max-width:600px">
        <div class="config-card-title" style="margin-bottom:0.5rem">📤 Enviar Paz y Salvo a Talento Humano</div>
        <div class="alert-banner warning" style="margin-bottom:0">
          <span>⏳</span>
          <div>
            Tu paz y salvo aún <strong>no está completamente aprobado</strong>.<br>
            Podrás enviarlo a Talento Humano una vez que todas las áreas lo aprueben.<br>
            Ve a <strong>Mi Estado</strong> para ver el progreso.
          </div>
        </div>
      </div>`;
    return;
  }

  // Paz y salvo completo: mostrar botón
  container.innerHTML = `
    <div class="config-card" style="max-width:600px">
      <div class="config-card-title" style="margin-bottom:0.5rem">📤 Enviar Paz y Salvo a Talento Humano</div>
      <div class="config-card-desc" style="margin-bottom:1.25rem">
        Tu paz y salvo está <strong style="color:var(--green)">completamente aprobado</strong>.
        Usa este botón para notificar al área de Talento Humano y que puedan registrarlo en nómina.
      </div>
      <div class="alert-banner info" style="margin-bottom:1.25rem">
        <span>ℹ️</span>
        <div>Esta acción envía un correo formal a Talento Humano con el detalle de tu paz y salvo.
        No es para consultas ni comunicación general.</div>
      </div>
      <button class="btn btn-success btn-lg" onclick="enviarSolicitudTH()">
        📤 Enviar Paz y Salvo a Talento Humano
      </button>
      <div id="th-enviado-msg" style="display:none; margin-top:1rem"></div>
    </div>`;
  window._thCedula = cedula;
}

async function enviarSolicitudTH() {
  const cedula = window._thCedula || STATE.cedulaPropia || STATE.username;
  const ok = await confirm(
    "Confirmar envío",
    "¿Enviar tu paz y salvo finalizado al área de Talento Humano? Esta acción generará un correo oficial.",
    "Enviar", false
  );
  if (!ok) return;

  const r = await api("enviar_solicitud_th", { cedula });
  const msgEl = document.getElementById("th-enviado-msg");

  if (r.ok) {
    toast(r.mensaje, "success", 6000);
    if (msgEl) {
      msgEl.style.display = "block";
      msgEl.innerHTML = `<div class="alert-banner success"><span>✅</span><div>${r.mensaje}</div></div>`;
    }
    const btnTH = document.querySelector("#th-panel-content button.btn-success");
    if (btnTH) btnTH.disabled = true;
  } else {
    toast(r.error, "error");
  }
}

// ═══════════════════════════════════════════════════════
// ADMIN — COLABORADORES (con selección múltiple)
// ═══════════════════════════════════════════════════════
async function loadAreaColaboradores() {
  const container = document.getElementById("area-table-container");
  container.innerHTML = '<div class="table-loading">Cargando...</div>';

  const r = await api("get_colaboradores_area");
  if (!r.ok) { container.innerHTML = `<div class="table-empty">${r.error}</div>`; return; }

  // Cache all areas
  STATE.areaColabs = {};
  (r.areas || []).forEach(a => { STATE.areaColabs[a.areaId] = a; });

  // Render area tabs if managing more than one area
  const tabsRow = document.getElementById("area-tabs-row");
  if (r.areas && r.areas.length > 1) {
    tabsRow.style.display = "flex";
    tabsRow.innerHTML = r.areas.map(a => `
      <button class="filter-chip area-tab ${a.areaId === STATE.currentAreaId ? "active" : ""}"
        onclick="switchAreaTab('${a.areaId}')">${a.areaNombre}</button>
    `).join("");
  } else {
    tabsRow.style.display = "none";
    if (r.areas && r.areas.length === 1) STATE.currentAreaId = r.areas[0].areaId;
  }

  // Load current area
  if (!STATE.currentAreaId && r.areas && r.areas.length) STATE.currentAreaId = r.areas[0].areaId;
  _renderAreaPanel(STATE.currentAreaId);
}

function switchAreaTab(areaId) {
  STATE.currentAreaId  = areaId;
  STATE.adminSelectedIds = new Set();
  updateAdminBulkBar();
  // Update tab active state
  document.querySelectorAll(".area-tab").forEach(t => {
    t.classList.toggle("active", t.textContent.trim() === (STATE.areaColabs[areaId] || {}).areaNombre);
  });
  _renderAreaPanel(areaId);
}

function _renderAreaPanel(areaId) {
  const areaData = STATE.areaColabs[areaId];
  if (!areaData) return;

  STATE.areaColaboradores = areaData.colaboradores;
  STATE.adminSelectedIds  = new Set();
  updateAdminBulkBar();

  document.getElementById("area-panel-title").textContent = `Colaboradores · ${areaData.areaNombre}`;

  const total     = areaData.colaboradores.length;
  const aprobados  = areaData.colaboradores.filter(c => c.estado === "APROBADO").length;
  const rechazados = areaData.colaboradores.filter(c => c.estado === "RECHAZADO").length;
  const pendientes = areaData.colaboradores.filter(c => c.estado === "PENDIENTE").length;

  document.getElementById("area-stats-row").innerHTML = `
    <div class="stat-card"><div class="stat-label">Total</div><div class="stat-value">${total}</div></div>
    <div class="stat-card green"><div class="stat-label">Aprobados</div><div class="stat-value" style="color:var(--green)">${aprobados}</div></div>
    <div class="stat-card"><div class="stat-label">Pendientes</div><div class="stat-value" style="color:var(--yellow)">${pendientes}</div></div>
    <div class="stat-card"><div class="stat-label">Rechazados</div><div class="stat-value" style="color:var(--red)">${rechazados}</div></div>
  `;

  renderAreaTable();
}

function renderAreaTable() {
  const container = document.getElementById("area-table-container");
  const search    = document.getElementById("area-search").value.toLowerCase();
  let lista = STATE.areaColaboradores;

  if (STATE.areaFilter !== "todos") lista = lista.filter(c => c.estado === STATE.areaFilter);
  if (search) lista = lista.filter(c =>
    c.nombre.toLowerCase().includes(search) || String(c.cedula).includes(search)
  );

  if (!lista.length) {
    container.innerHTML = '<div class="table-empty">No hay colaboradores con estos criterios</div>';
    return;
  }

  const allSelected = lista.length > 0 && lista.every(c => STATE.adminSelectedIds.has(c.id));

  container.innerHTML = `
    <table class="table">
      <thead><tr>
        <th class="col-check">
          <input type="checkbox" class="cb-custom" id="admin-cb-all"
            ${allSelected ? "checked" : ""} onchange="toggleAdminSelectAll(this.checked, ${JSON.stringify(lista.map(c=>c.id))})">
        </th>
        <th>Nombre</th><th>Cédula</th><th>Estado</th><th>Aprobado por</th><th>Acción</th>
      </tr></thead>
      <tbody>
        ${lista.map(c => `
          <tr class="${STATE.adminSelectedIds.has(c.id) ? "row-selected" : ""}">
            <td><input type="checkbox" class="cb-custom" ${STATE.adminSelectedIds.has(c.id) ? "checked" : ""}
              onchange="toggleAdminSelect('${c.id}', this.checked)"></td>
            <td>${c.nombre}</td>
            <td><span style="font-family:var(--font-mono); font-size:0.82rem">${c.cedula}</span></td>
            <td><span class="badge badge-${c.estado.toLowerCase()}">${c.estado}</span></td>
            <td style="color:var(--text2); font-size:0.82rem">${c.aprobadoPor || "—"}</td>
            <td><button class="btn btn-ghost btn-sm" onclick="abrirGestionar('${c.id}')">Gestionar</button></td>
          </tr>
        `).join("")}
      </tbody>
    </table>
  `;
}

function toggleAdminSelect(id, checked) {
  if (checked) STATE.adminSelectedIds.add(id);
  else         STATE.adminSelectedIds.delete(id);
  updateAdminBulkBar();
  renderAreaTable();
}

function toggleAdminSelectAll(checked, ids) {
  ids.forEach(id => { if (checked) STATE.adminSelectedIds.add(id); else STATE.adminSelectedIds.delete(id); });
  updateAdminBulkBar();
  renderAreaTable();
}

function updateAdminBulkBar() {
  const n   = STATE.adminSelectedIds.size;
  const bar = document.getElementById("admin-bulk-bar");
  bar.classList.toggle("visible", n > 0);
  document.getElementById("admin-bulk-count").textContent = `${n} seleccionado${n !== 1 ? "s" : ""}`;
}

async function aprobarMasivo() {
  const ids = [...STATE.adminSelectedIds];
  if (!ids.length) { toast("Selecciona al menos un colaborador", "error"); return; }

  const ok = await confirm("Aprobar múltiples",
    `¿Confirmas aprobar ${ids.length} colaborador(es) en tu área?`, "Aprobar todos");
  if (!ok) return;

  const r = await api("aprobar_masivo", { colaboradorIds: ids, areaId: STATE.currentAreaId });
  if (r.ok) {
    toast(r.mensaje, "success");
    STATE.adminSelectedIds = new Set();
    updateAdminBulkBar();
    loadAreaColaboradores();
  } else {
    toast(r.error, "error");
  }
}

function filtrarArea(estado, el) {
  if (estado !== null) {
    STATE.areaFilter = estado;
    document.querySelectorAll(".filter-chip").forEach(c => c.classList.remove("active"));
    if (el) el.classList.add("active");
  }
  renderAreaTable();
}

async function abrirGestionar(colabId) {
  STATE.gestionarColabId = colabId;
  const c = STATE.areaColaboradores.find(x => x.id === colabId);
  if (!c) return;

  const content = document.getElementById("modal-gestionar-content");
  content.innerHTML = `
    <div class="modal-info-row"><span class="modal-info-label">Nombre</span><span class="modal-info-value">${c.nombre}</span></div>
    <div class="modal-info-row"><span class="modal-info-label">Cédula</span><span class="modal-info-value" style="font-family:var(--font-mono)">${c.cedula}</span></div>
    <div class="modal-info-row"><span class="modal-info-label">Estado en tu área</span><span><span class="badge badge-${c.estado.toLowerCase()}">${c.estado}</span></span></div>
    ${c.observaciones ? `<div class="modal-info-row"><span class="modal-info-label">Observaciones</span><span style="color:var(--red); font-size:0.85rem">${c.observaciones}</span></div>` : ""}
    <div id="gestionar-areas-estado" style="margin-top:1rem">
      <div style="font-size:0.78rem; color:var(--text3); padding:0.5rem 0">Cargando estado general...</div>
    </div>
  `;
  document.getElementById("modal-obs-group").style.display = "none";
  document.getElementById("modal-observaciones").value     = "";
  abrirModal("modal-gestionar");

  const r = await api("get_estado_colaborador", { colaboradorId: colabId });
  const box = document.getElementById("gestionar-areas-estado");
  if (!box) return;
  if (!r.ok) { box.innerHTML = `<div style="font-size:0.8rem; color:var(--text3)">${r.error}</div>`; return; }

  const areasRequeridas = r.estadoPorArea.filter(a => a.estado !== "OMITIDO");
  const pendientes = areasRequeridas.filter(a => a.estado !== "APROBADO");
  box.innerHTML = `
    <div style="font-size:0.8rem; font-weight:600; color:var(--text2); margin-bottom:0.5rem">
      Estado general · ${areasRequeridas.filter(a => a.estado === "APROBADO").length}/${areasRequeridas.length} áreas aprobadas
    </div>
    <div style="display:flex; flex-direction:column; gap:4px; max-height:180px; overflow-y:auto">
      ${r.estadoPorArea.map(a => `
        <div style="display:flex; justify-content:space-between; align-items:center; padding:4px 8px; background:var(--surface2); border-radius:6px">
          <span style="font-size:0.78rem">${a.areaNombre}</span>
          <span class="badge badge-${a.estado.toLowerCase()}" style="font-size:0.65rem">${a.estado}</span>
        </div>
      `).join("")}
    </div>
    ${pendientes.length > 0 ? `
      <button class="btn btn-ghost btn-sm" style="margin-top:0.75rem; width:100%"
        onclick="enviarRecordatorio('${colabId}', '${c.nombre.replace(/'/g,"\\'")}')">
        📧 Enviar recordatorio a áreas pendientes (${pendientes.length})
      </button>
    ` : `<div style="margin-top:0.75rem; font-size:0.78rem; color:var(--green)">✓ Todas las áreas aprobadas</div>`}
  `;
}

async function ejecutarAprobar() {
  const ok = await confirm("Confirmar aprobación", "¿Confirmas aprobar el paz y salvo de este colaborador en tu área?", "Aprobar");
  if (!ok) return;
  const r = await api("aprobar", { colaboradorId: STATE.gestionarColabId, areaId: STATE.currentAreaId });
  if (r.ok) { toast(r.mensaje, "success"); cerrarModal("modal-gestionar"); loadAreaColaboradores(); }
  else toast(r.error, "error");
}

async function ejecutarRechazar() {
  const obsGroup = document.getElementById("modal-obs-group");
  if (obsGroup.style.display === "none") { obsGroup.style.display = "block"; toast("Ingresa las observaciones antes de rechazar", "info"); return; }
  const obs = document.getElementById("modal-observaciones").value.trim();
  if (obs.length < 5) { toast("Las observaciones son obligatorias (mínimo 5 caracteres)", "error"); return; }
  const ok = await confirm("Confirmar rechazo", "¿Confirmas rechazar el paz y salvo de este colaborador?", "Rechazar", true);
  if (!ok) return;
  const r = await api("rechazar", { colaboradorId: STATE.gestionarColabId, observaciones: obs, areaId: STATE.currentAreaId });
  if (r.ok) { toast(r.mensaje, "success"); cerrarModal("modal-gestionar"); loadAreaColaboradores(); }
  else toast(r.error, "error");
}

// ═══════════════════════════════════════════════════════
// ADMIN — CONFIGURACIÓN
// ═══════════════════════════════════════════════════════
async function loadAdminConfig() {
  const r = await api("get_config_admin");
  if (r.ok) {
    document.getElementById("admin-emails-notif").value = r.emailsNotificacion || "";
  } else {
    console.warn("loadAdminConfig:", r.error);
  }
}

async function guardarEmailsNotificacion() {
  const emails = document.getElementById("admin-emails-notif").value.trim();
  if (emails && !emails.includes("@")) { toast("Correo inválido", "error"); return; }
  const r = await api("set_emails_notificacion", { emails });
  if (r.ok) toast(r.mensaje, "success");
  else toast(r.error, "error");
}

async function cambiarPasswordAdmin() {
  const actual    = document.getElementById("admin-pw-actual").value;
  const nueva     = document.getElementById("admin-pw-nueva").value;
  const confirmar = document.getElementById("admin-pw-confirmar").value;
  if (!actual || !nueva || !confirmar) { toast("Completa todos los campos", "error"); return; }
  if (nueva !== confirmar) { toast("Las contraseñas nuevas no coinciden", "error"); return; }
  if (nueva.length < 6)   { toast("La nueva contraseña debe tener al menos 6 caracteres", "error"); return; }
  const r = await api("cambiar_password", { passwordActual: actual, passwordNueva: nueva });
  if (r.ok) {
    toast(r.mensaje, "success");
    document.getElementById("admin-pw-actual").value = "";
    document.getElementById("admin-pw-nueva").value  = "";
    document.getElementById("admin-pw-confirmar").value = "";
  } else toast(r.error, "error");
}

// ═══════════════════════════════════════════════════════
// SUPER ADMIN — COLABORADORES (selección múltiple + descarga PS)
// ═══════════════════════════════════════════════════════
async function loadSAColaboradores() {
  const container = document.getElementById("sa-collab-table-container");
  container.innerHTML = '<div class="table-loading">Cargando...</div>';
  const r = await api("get_all_colaboradores");
  if (!r.ok) { container.innerHTML = `<div class="table-empty">${r.error}</div>`; return; }

  STATE.saColaboradores = r.colaboradores;
  STATE.saSelectedIds   = new Set();
  updateSABulkBar();
  renderSAColaboradoresTable();
}

function renderSAColaboradoresTable() {
  const container = document.getElementById("sa-collab-table-container");
  const lista     = STATE.saColaboradores;

  if (!lista.length) { container.innerHTML = '<div class="table-empty">No hay colaboradores registrados</div>'; return; }

  const allSelected = lista.length > 0 && lista.every(c => STATE.saSelectedIds.has(c.id));

  container.innerHTML = `
    <table class="table">
      <thead><tr>
        <th class="col-check">
          <input type="checkbox" class="cb-custom" ${allSelected ? "checked" : ""}
            onchange="toggleSASelectAll(this.checked)">
        </th>
        <th>Nombre</th><th>Cédula</th><th>Área</th><th>Estado</th><th>Paz y Salvo</th><th>Activo</th><th>Acciones</th>
      </tr></thead>
      <tbody>
        ${lista.map(c => {
          const escapedNombre    = c.nombre.replace(/'/g,"\\'");
          const escapedAreasReq  = (c.areasRequeridas || "").replace(/'/g,"\\'");
          const tipoLabel = { DOCENTE: "Docente", ADMINISTRATIVO: "Administrativo", SERVICIOS: "Servicios" }[c.tipoColaborador] || "—";
          const tipoColor = { DOCENTE: "var(--blue)", ADMINISTRATIVO: "var(--green)", SERVICIOS: "var(--yellow)" }[c.tipoColaborador] || "var(--text2)";
          return `
          <tr class="${STATE.saSelectedIds.has(c.id) ? "row-selected" : ""}">
            <td><input type="checkbox" class="cb-custom" ${STATE.saSelectedIds.has(c.id) ? "checked" : ""}
              onchange="toggleSASelect('${c.id}', this.checked)"></td>
            <td>${c.nombre}</td>
            <td><span style="font-family:var(--font-mono); font-size:0.82rem">${c.cedula}</span></td>
            <td style="font-size:0.8rem; color:${tipoColor}">${tipoLabel}</td>
            <td><span class="badge badge-${c.estadoGeneral === "COMPLETO" ? "aprobado" : "pendiente"}">${c.estadoGeneral}</span></td>
            <td>
              <label class="switch-wrap">
                <label class="switch">
                  <input type="checkbox" ${c.requierePazSalvo ? "checked" : ""} onchange="togglePazSalvo('${c.id}', this.checked)">
                  <span class="switch-track"></span><span class="switch-thumb"></span>
                </label>
                <span style="font-size:0.8rem; color:var(--text2)">${c.requierePazSalvo ? "Sí" : "No"}</span>
              </label>
            </td>
            <td><span class="badge ${c.activo ? "badge-aprobado" : "badge-inactivo"}">${c.activo ? "Activo" : "Inactivo"}</span></td>
            <td style="display:flex; gap:6px; flex-wrap:wrap">
              <button class="btn btn-ghost btn-sm" onclick="abrirModalEditarColaborador('${c.id}','${escapedNombre}','${c.cedula}',${c.activo},'${c.tipoColaborador || ""}','${c.nivelEducativo || ""}','${escapedAreasReq}')">Editar</button>
              ${c.tieneDocumento ? `<button class="btn btn-success btn-sm" onclick="descargarDocumento('${c.id}')">📄 PS</button>` : ""}
            </td>
          </tr>`;
        }).join("")}
      </tbody>
    </table>
  `;
}

function toggleSASelect(id, checked) {
  if (checked) STATE.saSelectedIds.add(id);
  else         STATE.saSelectedIds.delete(id);
  updateSABulkBar();
  renderSAColaboradoresTable();
}

function toggleSASelectAll(checked) {
  STATE.saColaboradores.forEach(c => {
    if (checked) STATE.saSelectedIds.add(c.id);
    else         STATE.saSelectedIds.delete(c.id);
  });
  updateSABulkBar();
  renderSAColaboradoresTable();
}

function updateSABulkBar() {
  const n   = STATE.saSelectedIds.size;
  const bar = document.getElementById("sa-bulk-bar");
  bar.classList.toggle("visible", n > 0);
  document.getElementById("sa-bulk-count").textContent = `${n} seleccionado${n !== 1 ? "s" : ""}`;
}

async function togglePazSalvoMasivo(valor) {
  const ids = [...STATE.saSelectedIds];
  if (!ids.length) { toast("Selecciona al menos un colaborador", "error"); return; }
  const accion = valor ? "activar" : "desactivar";
  const ok = await confirm(`${valor ? "Activar" : "Desactivar"} paz y salvo`,
    `¿${accion.charAt(0).toUpperCase() + accion.slice(1)} el requerimiento de paz y salvo para ${ids.length} colaborador(es)?${valor ? " Se notificará a los administradores por correo." : ""}`,
    "Confirmar", !valor);
  if (!ok) return;
  const r = await api("toggle_paz_salvo_masivo", { ids, valor });
  if (r.ok) {
    toast(r.mensaje, "success");
    STATE.saSelectedIds = new Set();
    updateSABulkBar();
    loadSAColaboradores();
  } else toast(r.error, "error");
}

// tipo: "DOCENTE" → solo áreas DEPARTAMENTAL | "ADMINISTRATIVO" → todas | "" → oculto
function populateColabAreasSelect(selectedId = "", tipo = "") {
  const sel = document.getElementById("colab-areas-requeridas");
  const selected = String(selectedId).trim();
  const todas = STATE.areasDisponibles || [];

  let opciones;
  if (tipo === "DOCENTE") {
    const depto = todas.filter(a => a.tipo === "DEPARTAMENTAL");
    opciones = depto.length > 0 ? depto : todas; // fallback antes de migración
  } else {
    opciones = todas; // para ADMINISTRATIVO mostrar todas las áreas disponibles
  }

  const emptyLabel = tipo === "DOCENTE"
    ? "— Sin área académica —"
    : "— Sin jefe asignado —";

  sel.innerHTML = `<option value="">${emptyLabel}</option>` +
    opciones.map(a =>
      `<option value="${a.id}" ${String(a.id) === selected ? "selected" : ""}>${a.nombre}</option>`
  ).join("");
}

function onChangeTipoColab(tipo) {
  const nivelGroup = document.getElementById("colab-nivel-group");
  const jefeGroup  = document.getElementById("colab-jefe-group");
  const jefeLabel  = document.getElementById("colab-jefe-label");
  const jefeHint   = document.getElementById("colab-jefe-hint");

  nivelGroup.style.display = tipo === "DOCENTE" ? "block" : "none";
  jefeGroup.style.display  = (tipo === "DOCENTE" || tipo === "ADMINISTRATIVO") ? "block" : "none";

  if (tipo === "DOCENTE") {
    jefeLabel.textContent = "Área académica";
    jefeHint.textContent  = "Jefe de área responsable de la firma (Matemáticas, Inglés, etc.).";
  } else if (tipo === "ADMINISTRATIVO") {
    jefeLabel.textContent = "Jefe inmediato / Supervisor";
    jefeHint.textContent  = "Supervisor directo: Andrea (Talento Humano), David (Jefe de Área), Doña Sonia (Coord. Administrativa), etc.";
  }

  // Refrescar opciones del dropdown (sin preservar selección al cambiar de tipo)
  populateColabAreasSelect("", tipo);
}

function abrirModalCrearColaborador() {
  STATE.colabEditId = null;
  document.getElementById("modal-colab-title").textContent    = "Nuevo colaborador";
  document.getElementById("colab-nombre").value               = "";
  document.getElementById("colab-cedula").value               = "";
  document.getElementById("colab-username").value             = "";
  document.getElementById("colab-password").value             = "";
  document.getElementById("colab-requiere-ps").checked        = true;
  document.getElementById("colab-tipo").value                 = "";
  document.getElementById("colab-nivel").value                = "";
  document.getElementById("colab-activo-group").style.display = "none";
  document.getElementById("colab-acceso-group").style.display = "block";
  document.getElementById("colab-nivel-group").style.display  = "none";
  document.getElementById("colab-jefe-group").style.display   = "none";
  document.getElementById("colab-edit-id").value              = "";
  populateColabAreasSelect("", "");
  document.getElementById("colab-cedula").oninput = function() {
    if (!document.getElementById("colab-username").value)
      document.getElementById("colab-username").value = this.value;
  };
  abrirModal("modal-colaborador");
}

function abrirModalEditarColaborador(id, nombre, cedula, activo, tipoColaborador = "", nivelEducativo = "", areasRequeridas = "") {
  STATE.colabEditId = id;
  document.getElementById("modal-colab-title").textContent    = "Editar colaborador";
  document.getElementById("colab-nombre").value               = nombre;
  document.getElementById("colab-cedula").value               = cedula;
  document.getElementById("colab-tipo").value                 = tipoColaborador || "";
  document.getElementById("colab-nivel").value                = nivelEducativo || "";
  document.getElementById("colab-activo-group").style.display = "block";
  document.getElementById("colab-activo").value               = activo ? "true" : "false";
  document.getElementById("colab-acceso-group").style.display = "none";
  document.getElementById("colab-nivel-group").style.display  = tipoColaborador === "DOCENTE" ? "block" : "none";
  document.getElementById("colab-jefe-group").style.display   = (tipoColaborador === "DOCENTE" || tipoColaborador === "ADMINISTRATIVO") ? "block" : "none";
  document.getElementById("colab-edit-id").value              = id;
  document.getElementById("colab-cedula").oninput             = null;
  // Actualizar labels sin resetear selección
  const jefeLabel = document.getElementById("colab-jefe-label");
  const jefeHint  = document.getElementById("colab-jefe-hint");
  if (tipoColaborador === "DOCENTE") {
    if (jefeLabel) jefeLabel.textContent = "Área académica";
    if (jefeHint)  jefeHint.textContent  = "Jefe de área responsable de la firma (Matemáticas, Inglés, etc.).";
  } else if (tipoColaborador === "ADMINISTRATIVO") {
    if (jefeLabel) jefeLabel.textContent = "Jefe inmediato / Supervisor";
    if (jefeHint)  jefeHint.textContent  = "Supervisor directo: Andrea (Talento Humano), David (Jefe de Área), Doña Sonia (Coord. Administrativa), etc.";
  }
  populateColabAreasSelect(areasRequeridas, tipoColaborador);
  abrirModal("modal-colaborador");
}

async function guardarColaborador() {
  const nombre    = document.getElementById("colab-nombre").value.trim();
  const cedula    = document.getElementById("colab-cedula").value.trim();
  const requiere  = document.getElementById("colab-requiere-ps").checked;
  const id        = document.getElementById("colab-edit-id").value;
  const tipoColaborador = document.getElementById("colab-tipo").value;
  const nivelEducativo  = document.getElementById("colab-nivel").value;
  const areasRequeridas = document.getElementById("colab-areas-requeridas").value.trim();

  if (!nombre || !cedula) { toast("Nombre y cédula son obligatorios", "error"); return; }
  if (!tipoColaborador)   { toast("Selecciona el tipo de colaborador", "error"); return; }

  if (!id) {
    const username = document.getElementById("colab-username").value.trim();
    const password = document.getElementById("colab-password").value;
    if (!username) { toast("El usuario de acceso es obligatorio", "error"); return; }
    if (!password || password.length < 6) { toast("La contraseña debe tener al menos 6 caracteres", "error"); return; }
    const ok = await confirm("Confirmar", `¿Crear colaborador "${nombre}" como ${tipoColaborador.toLowerCase()}?`, "Crear");
    if (!ok) return;
    const rColab = await api("crear_colaborador", { nombre, cedula, requierePazSalvo: requiere, tipoColaborador, nivelEducativo, areasRequeridas });
    if (!rColab.ok) { toast(rColab.error, "error"); return; }
    const rUser  = await api("crear_usuario", { username, password, rol: "COLABORADOR", areaId: "" });
    if (!rUser.ok) toast(`Colaborador creado pero error al crear usuario: ${rUser.error}`, "error");
    else toast(`${nombre} creado con usuario "${username}" ✓`, "success");
    cerrarModal("modal-colaborador");
    loadSAColaboradores();
    return;
  }

  const ok = await confirm("Confirmar", "¿Guardar cambios del colaborador?", "Guardar");
  if (!ok) return;
  const activo = document.getElementById("colab-activo").value === "true";
  const r = await api("editar_colaborador", { id, nombre, cedula, activo, tipoColaborador, nivelEducativo, areasRequeridas });
  if (r.ok) { toast(r.mensaje, "success"); cerrarModal("modal-colaborador"); loadSAColaboradores(); }
  else toast(r.error, "error");
}

async function togglePazSalvo(id, valor) {
  const ok = await confirm("Confirmar",
    `¿${valor ? "Activar" : "Desactivar"} el requerimiento de paz y salvo?${valor ? " Se notificará a los administradores." : ""}`,
    "Confirmar");
  if (!ok) { loadSAColaboradores(); return; }
  const r = await api("toggle_paz_salvo", { id, valor });
  if (r.ok) toast(r.mensaje, "success");
  else toast(r.error, "error");
  loadSAColaboradores();
}

