function descargarPlantilla() {
  if (!window.XLSX) { toast("Librería Excel no disponible, recarga la página", "error"); return; }

  const wb = XLSX.utils.book_new();

  // Hoja de datos
  const datos = [
    ["NOMBRE", "CEDULA", "USERNAME", "PASSWORD", "REQUIERE_PAZ_SALVO"],
    ["María García",  "12345678", "maria.garcia", "Goyavier2026#", "SI"],
    ["Juan Pérez",    "87654321", "juan.perez",   "Goyavier2026#", "SI"],
    ["Ana Martínez",  "11223344", "",             "",              "NO"],
  ];
  const ws = XLSX.utils.aoa_to_sheet(datos);

  ws["!cols"] = [
    { wch: 32 }, // NOMBRE
    { wch: 14 }, // CEDULA
    { wch: 22 }, // USERNAME
    { wch: 18 }, // PASSWORD
    { wch: 20 }, // REQUIERE_PAZ_SALVO
  ];

  // Hoja de instrucciones
  const inst = XLSX.utils.aoa_to_sheet([
    ["INSTRUCCIONES DE LA PLANTILLA"],
    [""],
    ["COLUMNA",              "OBLIGATORIO", "DESCRIPCIÓN"],
    ["NOMBRE",               "SÍ",          "Nombre completo del colaborador"],
    ["CEDULA",               "SÍ",          "Número de cédula (solo números, sin puntos ni comas)"],
    ["USERNAME",             "No",          "Usuario para ingresar al sistema. Si se deja vacío se usará la cédula"],
    ["PASSWORD",             "No",          "Contraseña inicial. Si se deja vacío se usará la cédula"],
    ["REQUIERE_PAZ_SALVO",   "No",          "SI o NO. Si se deja vacío se asume SI"],
    [""],
    ["NOTAS"],
    ["• Máximo 200 filas por carga"],
    ["• No borres la fila de encabezados (fila 1)"],
    ["• La cédula no puede repetirse"],
    ["• El USERNAME no puede repetirse"],
    ["• Guarda como .xlsx antes de subir"],
  ]);
  inst["!cols"] = [{ wch: 24 }, { wch: 14 }, { wch: 55 }];

  XLSX.utils.book_append_sheet(wb, ws,   "Colaboradores");
  XLSX.utils.book_append_sheet(wb, inst, "Instrucciones");
  XLSX.writeFile(wb, "plantilla_colaboradores.xlsx");
  toast("Plantilla descargada ✓", "success");
}

function handleFileDrop(e) {
  e.preventDefault();
  document.getElementById("upload-zone").classList.remove("drag-over");
  const file = e.dataTransfer.files[0];
  if (file) procesarArchivo(file);
}

function handleFileSelect(e) {
  const file = e.target.files[0];
  if (file) procesarArchivo(file);
}

function procesarArchivo(file) {
  if (file.size > 1024 * 1024) { toast("El archivo no debe superar 1 MB", "error"); return; }
  const ext = file.name.split(".").pop().toLowerCase();

  if (ext === "csv" || ext === "txt") {
    const reader = new FileReader();
    reader.onload = ev => procesarCSVTexto(ev.target.result);
    reader.readAsText(file, "UTF-8");
  } else if (ext === "xlsx" || ext === "xls") {
    if (!window.XLSX) { toast("Librería Excel no disponible, recarga la página", "error"); return; }
    const reader = new FileReader();
    reader.onload = ev => {
      try {
        const wb   = XLSX.read(new Uint8Array(ev.target.result), { type: "array" });
        const ws   = wb.Sheets[wb.SheetNames[0]];
        const filas = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });
        procesarFilas(filas);
      } catch(err) {
        toast("No se pudo leer el archivo Excel: " + err.message, "error");
      }
    };
    reader.readAsArrayBuffer(file);
  } else {
    toast("Formato no soportado. Usa .xlsx, .csv o .txt", "error");
  }
}

function procesarTextoMasivo() {
  const texto = document.getElementById("masiva-texto").value;
  if (!texto.trim()) { toast("Pega los datos antes de previsualizar", "error"); return; }
  procesarCSVTexto(texto);
}

function procesarCSVTexto(texto) {
  const lineas = texto.trim().split(/\r?\n/).filter(l => l.trim());
  // Detectar separador: si la primera línea tiene ; lo usamos, si no ","
  const sep = lineas[0].includes(";") ? ";" : ",";
  const filas = lineas.map(l => l.split(sep).map(c => c.trim().replace(/^"|"$/g, "")));
  procesarFilas(filas);
}

function procesarFilas(filas) {
  if (!filas.length) { toast("El archivo está vacío", "error"); return; }

  // Normalizar encabezados
  const HEADER_MAP = {
    nombre: "nombre", name: "nombre",
    cedula: "cedula", cédula: "cedula", documento: "cedula", "número de cédula": "cedula",
    username: "username", usuario: "username", user: "username",
    password: "password", contraseña: "password", clave: "password",
    requierepaz: "requierePazSalvo", requierepazysalvo: "requierePazSalvo",
    paz: "requierePazSalvo", "requiere paz y salvo": "requierePazSalvo",
    "requiere_paz_salvo": "requierePazSalvo",
  };

  let inicio = 0;
  const primeraFila = filas[0].map(c => String(c).toLowerCase().replace(/\s+/g,"").replace(/_/g,""));
  const esEncabezado = primeraFila.some(c => c === "nombre" || c === "cedula" || c === "cédula");

  let mapCol = {};  // { fieldName: colIndex }
  if (esEncabezado) {
    inicio = 1;
    primeraFila.forEach((h, i) => {
      const mapped = HEADER_MAP[h] || HEADER_MAP[h.replace(/[^a-z]/g,"")];
      if (mapped) mapCol[mapped] = i;
    });
  } else {
    // Sin encabezado: asume orden nombre,cedula,username,password,requierePazSalvo
    mapCol = { nombre: 0, cedula: 1, username: 2, password: 3, requierePazSalvo: 4 };
  }

  if (mapCol.nombre === undefined || mapCol.cedula === undefined) {
    toast("No se encontraron las columnas NOMBRE y CEDULA", "error"); return;
  }

  const registros = [];
  const errores   = [];

  filas.slice(inicio).forEach((cols, idx) => {
    const nombre  = String(cols[mapCol.nombre]  || "").trim();
    const cedula  = String(cols[mapCol.cedula]  || "").trim();
    if (!nombre && !cedula) return; // fila vacía
    if (!nombre || !cedula) { errores.push(`Fila ${inicio + idx + 2}: nombre o cédula vacíos`); return; }
    registros.push({
      nombre,
      cedula,
      username:         String(cols[mapCol.username]  || "").trim(),
      password:         String(cols[mapCol.password]  || "").trim(),
      requierePazSalvo: String(cols[mapCol.requierePazSalvo] || "SI").trim().toUpperCase() !== "NO"
    });
  });

  STATE.masivaRegistros = registros;

  const preview = document.getElementById("masiva-preview");
  preview.style.display = "block";
  preview.innerHTML = `
    <div style="margin-top:1rem">
      <div style="font-size:0.8rem; font-weight:600; color:var(--text2); margin-bottom:0.5rem">
        Previsualización — ${registros.length} registro(s) detectado(s)
        ${errores.length ? `<span style="color:var(--red); margin-left:8px">⚠ ${errores.length} con error</span>` : ""}
      </div>
      <div class="upload-preview">
        <div class="upload-preview-row" style="font-weight:600; color:var(--text)">
          <span style="flex:2">Nombre</span>
          <span style="flex:1">Cédula</span>
          <span style="flex:1">Usuario</span>
          <span style="flex:1">Requiere PS</span>
        </div>
        ${registros.slice(0, 10).map(r => `
          <div class="upload-preview-row">
            <span style="flex:2">${r.nombre}</span>
            <span style="flex:1; font-family:var(--font-mono); font-size:0.82rem">${r.cedula}</span>
            <span style="flex:1; color:var(--text2); font-size:0.82rem">${r.username || '<i style="color:var(--text3)">=cédula</i>'}</span>
            <span style="flex:1"><span class="badge ${r.requierePazSalvo ? "badge-aprobado" : "badge-inactivo"}">${r.requierePazSalvo ? "Sí" : "No"}</span></span>
          </div>
        `).join("")}
        ${registros.length > 10 ? `<div class="upload-preview-row" style="color:var(--text3)">… y ${registros.length - 10} más</div>` : ""}
      </div>
      ${errores.length ? `<div style="margin-top:0.5rem; font-size:0.78rem; color:var(--red)">⚠ Errores omitidos: ${errores.join(" · ")}</div>` : ""}
    </div>
  `;

  document.getElementById("btn-ejecutar-masiva").style.display = registros.length > 0 ? "inline-flex" : "none";
}

async function ejecutarCargaMasiva() {
  const registros = STATE.masivaRegistros;
  if (!registros.length) { toast("No hay registros para importar", "error"); return; }

  const ok = await confirm("Confirmar carga masiva",
    `¿Importar ${registros.length} colaborador(es)? Esta acción no se puede deshacer.`, "Importar");
  if (!ok) return;

  const btn = document.getElementById("btn-ejecutar-masiva");
  btn.disabled = true;
  btn.innerHTML = '<div class="loading-spinner" style="width:14px;height:14px;border-width:2px"></div> Importando...';

  const r = await api("carga_masiva_colaboradores", { registros });
  btn.disabled = false;
  btn.innerHTML = "✅ Importar colaboradores";

  const resultDiv = document.getElementById("masiva-result");
  resultDiv.style.display = "block";

  if (r.ok) {
    const tipo = r.errores.length ? "partial" : "success";
    resultDiv.className = `upload-result ${tipo}`;
    resultDiv.innerHTML = `
      <strong>${r.ok ? "✅" : "⚠️"} ${r.mensaje}</strong>
      ${r.creados.length ? `<ul>${r.creados.map(c => `<li>✓ ${c}</li>`).join("")}</ul>` : ""}
      ${r.omitidos.length ? `<div style="margin-top:0.5rem; color:var(--yellow); font-size:0.8rem">
        Omitidos: <ul>${r.omitidos.map(o => `<li>${o}</li>`).join("")}</ul></div>` : ""}
      ${r.errores.length ? `<div style="margin-top:0.5rem; color:var(--red); font-size:0.8rem">
        Errores: <ul>${r.errores.map(e => `<li>${e}</li>`).join("")}</ul></div>` : ""}
    `;
    toast(r.mensaje, r.errores.length ? "info" : "success");
    loadSAColaboradores();
  } else {
    resultDiv.className = "upload-result error";
    resultDiv.innerHTML = `<strong>❌ ${r.error}</strong>`;
    toast(r.error, "error");
  }
}

