async function loadCorreosSA() {
  // Cargar email TH
  const rc = await api("get_config");
  if (rc.ok) {
    document.getElementById("sa-email-th").value = rc.config.EMAIL_TALENTO_HUMANO || "";
  }

  // Cargar tabla de admins con sus correos
  const container = document.getElementById("sa-admins-emails-container");
  if (!container) return;

  const ru = await api("get_usuarios");
  if (!ru.ok) {
    container.innerHTML = `<div class="empty-state"><h3>${ru.error}</h3></div>`;
    return;
  }

  const admins = ru.usuarios.filter(u => u.rol === "ADMIN");
  if (!admins.length) {
    container.innerHTML = `<div class="empty-state"><h3>No hay Admins registrados</h3></div>`;
    return;
  }

  container.innerHTML = `
    <table class="table" style="margin-bottom:0">
      <thead><tr>
        <th>Admin (usuario)</th><th>Área</th><th>Estado</th><th>Correo de notificación</th><th>Acción</th>
      </tr></thead>
      <tbody>
        ${admins.map(u => {
          const areasLabel = (u.areaNombres && u.areaNombres.length) ? u.areaNombres.join(", ") : (u.areaNombre || "—");
          return `<tr>
            <td style="font-weight:500">${u.username}</td>
            <td style="font-size:0.85rem">${areasLabel}</td>
            <td><span class="badge ${u.activo ? "badge-aprobado" : "badge-inactivo"}">${u.activo ? "Activo" : "Inactivo"}</span></td>
            <td>
              <input type="email" id="admin-email-${u.id}" class="form-input"
                value="${u.email || ""}" placeholder="correo@colegio.edu.co"
                style="padding:6px 10px; font-size:0.82rem">
            </td>
            <td>
              <button class="btn btn-ghost btn-sm" onclick="guardarEmailAdmin('${u.id}')">💾 Guardar</button>
            </td>
          </tr>`;
        }).join("")}
      </tbody>
    </table>
    <div style="margin-top:0.75rem; font-size:0.78rem; color:var(--text2)">
      💡 Los Admins también pueden actualizar su correo desde su propio panel de Configuración.
    </div>
  `;
}

async function guardarEmailAdmin(userId) {
  const email = (document.getElementById("admin-email-" + userId) || {}).value || "";
  if (email && !email.includes("@")) { toast("Correo inválido", "error"); return; }
  const r = await api("editar_usuario", { id: userId, email });
  if (r.ok) toast("Correo guardado ✓", "success");
  else toast(r.error, "error");
}

async function guardarEmailTH() {
  const email = document.getElementById("sa-email-th").value.trim();
  if (email && !email.includes("@")) { toast("Correo inválido", "error"); return; }
  const r = await api("set_config_sa", { clave: "EMAIL_TALENTO_HUMANO", valor: email });
  if (r.ok) toast("Correo de Talento Humano guardado ✓", "success");
  else toast(r.error, "error");
}

