async function toggleProceso(valor) {
  const ok = await confirm(
    valor ? "Activar proceso" : "Desactivar proceso",
    valor
      ? "¿Activar el proceso de paz y salvo? Los usuarios podrán acceder al sistema."
      : "¿Desactivar el proceso? Los usuarios no podrán ingresar hasta que se reactive.",
    valor ? "Activar" : "Desactivar", !valor
  );
  if (!ok) { loadSAConfig(); return; }
  const r = await api("set_proceso_activo", { valor });
  if (r.ok) { toast(r.mensaje, "success"); loadSAConfig(); }
  else toast(r.error, "error");
}

async function ejecutarDiagnostico() {
  const el = document.getElementById("diagnostico-resultado");
  el.innerHTML = `<div class="empty-state" style="padding:0.5rem"><span class="loading-spinner"></span> Analizando...</div>`;
  const r = await api("diagnostico_aprobaciones", {});
  if (!r.ok) { el.innerHTML = `<div class="alert-banner error"><span>❌</span><div>${r.error}</div></div>`; return; }

  const s = r.resumen;
  const hayProblema = s.adminsConAreaIdInvalido > 0 || s.aprobacionesHuerfanas > 0;

  const adminsRows = (s.adminsCheck || []).map(a => `
    <tr>
      <td>${a.username}</td>
      <td><span class="badge ${a.existeEnAreas ? "badge-aprobado" : "badge-rechazado"}">${a.existeEnAreas ? "✓ OK" : "❌ INVÁLIDO"}</span></td>
      <td style="font-size:0.78rem; color:var(--text2)">${a.areaNombre}</td>
    </tr>`).join("");

  el.innerHTML = `
    <div class="alert-banner ${hayProblema ? "warning" : ""}" style="margin-bottom:0.75rem">
      <span>${hayProblema ? "⚠️" : "✅"}</span>
      <div><strong>${s.problema}</strong></div>
    </div>
    <div style="font-size:0.82rem; color:var(--text2); margin-bottom:0.5rem">
      Áreas activas: <strong>${s.areasActivasCount}</strong> &nbsp;|&nbsp;
      Admins con ID inválido: <strong style="color:${s.adminsConAreaIdInvalido ? "var(--red)" : "var(--green)"}">${s.adminsConAreaIdInvalido}</strong> &nbsp;|&nbsp;
      Aprobaciones huérfanas (todas las aprobaciones): <strong style="color:${s.aprobacionesHuerfanas ? "var(--red)" : "var(--green)"}">${s.aprobacionesHuerfanas}</strong>
    </div>
    <table class="table" style="font-size:0.82rem; margin-bottom:0">
      <thead><tr><th>Admin</th><th>Estado AREA_ID</th><th>Área mapeada</th></tr></thead>
      <tbody>${adminsRows}</tbody>
    </table>
  `;

  document.getElementById("btn-reparar-ids").style.display = hayProblema ? "inline-flex" : "none";
}

async function ejecutarRepararIds() {
  const ok = await confirm(
    "Reparar IDs de áreas",
    "Esto actualizará los AREA_IDs de los admins en USUARIOS y corregirá las APROBACIONES existentes. Esta acción no se puede deshacer. ¿Continuar?",
    "Reparar", true
  );
  if (!ok) return;

  const el = document.getElementById("diagnostico-resultado");
  el.innerHTML = `<div class="empty-state" style="padding:0.5rem"><span class="loading-spinner"></span> Reparando...</div>`;
  const r = await api("reparar_area_ids", {});
  if (!r.ok) { el.innerHTML = `<div class="alert-banner error"><span>❌</span><div>${r.error}</div></div>`; return; }

  const reparadosHtml = (r.reparados || []).map(x =>
    `<li>${x.username} → ${x.areaNombre}</li>`).join("");
  const sinResolverHtml = (r.sinResolver || []).map(x =>
    `<li>${x.username} (actualiza AREA_ID manualmente)</li>`).join("");

  el.innerHTML = `
    <div class="alert-banner" style="margin-bottom:0.75rem">
      <span>✅</span><div><strong>${r.mensaje}</strong><br>${r.nota}</div>
    </div>
    ${reparadosHtml ? `<ul style="font-size:0.82rem; margin:0.5rem 0 0 1rem">${reparadosHtml}</ul>` : ""}
    ${sinResolverHtml ? `<div style="margin-top:0.5rem; font-size:0.82rem; color:var(--yellow)">Sin resolver:<ul style="margin:0.25rem 0 0 1rem">${sinResolverHtml}</ul></div>` : ""}
  `;
  document.getElementById("btn-reparar-ids").style.display = "none";
  toast(r.mensaje, "success");
}

async function cambiarPasswordSA() {
  const actual    = document.getElementById("sa-pw-actual").value;
  const nueva     = document.getElementById("sa-pw-nueva").value;
  const confirmar = document.getElementById("sa-pw-confirmar").value;
  if (!actual || !nueva || !confirmar) { toast("Completa todos los campos", "error"); return; }
  if (nueva !== confirmar) { toast("Las contraseñas nuevas no coinciden", "error"); return; }
  if (nueva.length < 6)   { toast("La nueva contraseña debe tener al menos 6 caracteres", "error"); return; }
  const r = await api("cambiar_password", { passwordActual: actual, passwordNueva: nueva });
  if (r.ok) {
    toast(r.mensaje, "success");
    ["sa-pw-actual","sa-pw-nueva","sa-pw-confirmar"].forEach(id => document.getElementById(id).value = "");
  } else toast(r.error, "error");
}

