async function loadLogs() {
  const container = document.getElementById("sa-logs-content");
  container.innerHTML = '<div class="loading-state"><div class="loading-spinner"></div> Cargando...</div>';
  const r = await api("get_logs");
  if (!r.ok) { container.innerHTML = `<div class="table-empty">${r.error}</div>`; return; }
  if (!r.logs.length) { container.innerHTML = '<div class="table-empty">No hay registros</div>'; return; }

  container.innerHTML = `
    <div style="padding: 0.5rem 0.75rem; border-bottom:1px solid var(--border)">
      <div class="log-row" style="font-size:0.7rem; color:var(--text3); font-weight:600">
        <div>TIMESTAMP</div><div>USUARIO</div><div>ROL</div><div>ACCIÓN</div><div>DETALLE</div>
      </div>
    </div>
    <div style="padding: 0.25rem 0.75rem; max-height: 600px; overflow-y:auto">
      ${r.logs.map(l => `
        <div class="log-row">
          <div class="log-time">${l.timestamp}</div>
          <div class="log-user">${l.usuario}</div>
          <div style="color:var(--text2); font-size:0.75rem">${l.rol}</div>
          <div class="log-action">${l.accion}</div>
          <div class="log-detail" title="${l.detalle}">${l.detalle}</div>
        </div>
      `).join("")}
    </div>
  `;
}

